
document.addEventListener("DOMContentLoaded", function () {

  const button = document.getElementById("searchBtn");
  const articles = document.querySelectorAll(".article");

  // create no result message if not exists
  let noResults = document.getElementById("noResults");
  if (!noResults) {
    noResults = document.createElement("p");
    noResults.id = "noResults";
    noResults.style.color = "red";
    noResults.style.display = "none";
    noResults.innerText = "No Islamic articles found.";
    input.parentNode.appendChild(noResults);
  }

  function performSearch() {
    let value = input.value.toLowerCase().trim();
    let found = false;

    articles.forEach(article => {
      if (article.innerText.toLowerCase().includes(value)) {
        article.style.display = "block";
        found = true;
      } else {
        article.style.display = "none";
      }
    });

    if (!found && value !== "") {
      noResults.style.display = "block";
    } else {
      noResults.style.display = "none";
    }
  }

  if (input) {
    input.addEventListener("input", performSearch);
    input.addEventListener("keypress", function(e) {
      if (e.key === "Enter") {
        performSearch();
      }
    });
  }

  if (button) {
    button.addEventListener("click", performSearch);
  }

});


/* ================= BADAWY ACADEMY PROFESSIONAL PORTAL ================= */

(function(){

if(document.getElementById("academyPortalLoaded")) return;

document.addEventListener("DOMContentLoaded", function(){

/* ---------- UI INJECTION ---------- */

const academySection = document.createElement("section");
academySection.id = "academyPortalLoaded";
academySection.innerHTML = `
<section style="margin:60px 0;padding:40px;background:#f1f5f9;border-radius:14px;">
<h2 style="text-align:center;font-size:30px;margin-bottom:20px;">🎓 Badawy Academy Portal</h2>

<div id="authArea" style="max-width:500px;margin:auto;background:white;padding:30px;border-radius:12px;box-shadow:0 6px 18px rgba(0,0,0,0.1);">
<h3>Register</h3>
<input id="regName" placeholder="Full Name" style="width:100%;padding:10px;margin:8px 0;border-radius:6px;border:1px solid #ccc;">
<input id="regPass" type="password" placeholder="Password" style="width:100%;padding:10px;margin:8px 0;border-radius:6px;border:1px solid #ccc;">
<button onclick="academyRegister()" style="width:100%;padding:10px;background:#0a7d4f;color:white;border:none;border-radius:6px;margin-top:10px;">Register</button>
<hr style="margin:20px 0;">
<h3>Login</h3>
<input id="loginName" placeholder="Full Name" style="width:100%;padding:10px;margin:8px 0;border-radius:6px;border:1px solid #ccc;">
<input id="loginPass" type="password" placeholder="Password" style="width:100%;padding:10px;margin:8px 0;border-radius:6px;border:1px solid #ccc;">
<button onclick="academyLogin()" style="width:100%;padding:10px;background:#1e293b;color:white;border:none;border-radius:6px;margin-top:10px;">Login</button>
</div>

<div id="dashboardArea" style="display:none;margin-top:30px;">
<div style="display:flex;gap:20px;flex-wrap:wrap;">
<div style="flex:1;min-width:200px;background:white;padding:20px;border-radius:10px;">
<h3>Student Info</h3>
<p id="studentInfo"></p>
<button onclick="academyLogout()" style="padding:6px 12px;background:#ef4444;color:white;border:none;border-radius:6px;">Logout</button>
</div>

<div style="flex:2;min-width:300px;background:white;padding:20px;border-radius:10px;">
<h3>Educational Library</h3>
<button onclick="loadQuranVerse()" style="padding:8px 14px;background:#0a7d4f;color:white;border:none;border-radius:6px;">Load Quran Verse</button>
<div id="eduContent" style="margin-top:15px;"></div>
</div>
</div>

<div style="margin-top:30px;background:white;padding:20px;border-radius:10px;">
<h3>Advanced Timed Quiz</h3>
<div id="quizArea"></div>
</div>

<div style="margin-top:30px;background:white;padding:20px;border-radius:10px;">
<h3>Certificate Center</h3>
<div id="certArea"></div>
</div>

</div>
</section>
`;

document.body.appendChild(academySection);

/* ---------- AUTH SYSTEM ---------- */

window.academyRegister = function(){
const name = document.getElementById("regName").value.trim();
const pass = document.getElementById("regPass").value.trim();
if(!name || !pass){ alert("Fill all fields"); return; }
const id = "BA-"+Math.floor(Math.random()*1000000);
localStorage.setItem("academyUser", JSON.stringify({name,pass,id,score:0}));
alert("Registered Successfully. Your ID: "+id);
}

window.academyLogin = function(){
const name = document.getElementById("loginName").value.trim();
const pass = document.getElementById("loginPass").value.trim();
const user = JSON.parse(localStorage.getItem("academyUser"));
if(!user || user.name!==name || user.pass!==pass){ alert("Invalid login"); return; }
document.getElementById("authArea").style.display="none";
document.getElementById("dashboardArea").style.display="block";
document.getElementById("studentInfo").innerHTML="Name: "+user.name+"<br>ID: "+user.id;
startQuiz();
}

window.academyLogout = function(){
location.reload();
}

/* ---------- EDUCATIONAL CONTENT (REAL QURAN API) ---------- */

window.loadQuranVerse = function(){
fetch("https://api.alquran.cloud/v1/ayah/"+(Math.floor(Math.random()*6236)+1))
.then(r=>r.json())
.then(d=>{
document.getElementById("eduContent").innerHTML=
"<p><strong>"+d.data.text+"</strong></p><p>Surah: "+d.data.surah.englishName+"</p>";
});
}

/* ---------- ADVANCED QUIZ ---------- */

const questions = [
{q:"Which Surah is known as the Heart of the Quran?",a:["Al-Fatiha","Yasin","Baqarah","Rahman"],c:1},
{q:"How many Rakats in Fajr?",a:["2","3","4","5"],c:0},
{q:"Battle of Badr occurred in which year Hijri?",a:["1","2","3","4"],c:1},
{q:"Which Prophet built the Kaaba?",a:["Musa","Isa","Ibrahim","Nuh"],c:2},
{q:"Zakat is what percentage of savings?",a:["1%","2.5%","5%","10%"],c:1}
];

let quizIndex=0, quizScore=0, timer=60, interval;

function startQuiz(){
quizIndex=0; quizScore=0;
renderQuestion();
}

function renderQuestion(){
if(quizIndex>=questions.length){ finishQuiz(); return; }
const q=questions[quizIndex];
let html="<p><strong>"+q.q+"</strong></p>";
q.a.forEach((opt,i)=>{
html+=`<button onclick="answerQuiz(${i})" style="display:block;margin:6px 0;padding:8px;border-radius:6px;">${opt}</button>`;
});
document.getElementById("quizArea").innerHTML=html;
}

window.answerQuiz=function(i){
if(i===questions[quizIndex].c) quizScore++;
quizIndex++;
renderQuestion();
}

function finishQuiz(){
let percent=Math.round((quizScore/questions.length)*100);
let status=percent>=70?"PASSED":"FAILED";
document.getElementById("quizArea").innerHTML=
"<h4>Score: "+quizScore+"/"+questions.length+"</h4><h4>"+percent+"% - "+status+"</h4>";
if(percent>=70) generateCertificate(percent);
}

/* ---------- CERTIFICATE ---------- */

function generateCertificate(percent){
const user=JSON.parse(localStorage.getItem("academyUser"));
const code="CERT-"+Math.floor(Math.random()*1000000);
const canvas=document.createElement("canvas");
canvas.width=800; canvas.height=600;
const ctx=canvas.getContext("2d");
ctx.fillStyle="#fff"; ctx.fillRect(0,0,800,600);
ctx.fillStyle="#0a7d4f"; ctx.font="36px Arial"; ctx.textAlign="center";
ctx.fillText("Badawy Academy Certificate",400,120);
ctx.font="24px Arial"; ctx.fillStyle="#000";
ctx.fillText("Awarded to: "+user.name,400,220);
ctx.fillText("Score: "+percent+"%",400,280);
ctx.fillText("Student ID: "+user.id,400,340);
ctx.fillText("Verification Code: "+code,400,400);
const link=document.createElement("a");
link.download="Badawy_Certificate.png";
link.href=canvas.toDataURL();
link.click();
document.getElementById("certArea").innerHTML="<p>Certificate Generated ✔</p>";
}

});

})();

/* ================= END BADAWY ACADEMY PORTAL ================= */

